EnablePrimaryMouseButtonEvents(true)
local recoil = false
local weapon = 0
function OnEvent(event, arg)
	if
		(event == "MOUSE_BUTTON_PRESSED" and arg == MACRO_OFF) or (event == "G_PRESSED" and arg == MACRO_OFF_Keyboard)
	then
		recoil = not recoil
		weapon = arg
		if recoil == false then
			OutputLogMessage("OFF-Dino.Com\n")
			if IsKeyLockOn("capslock") then
				PressAndReleaseKey("capslock")
			end
		else
			OutputLogMessage("OFF-Dino.Com\n")
