	local remainder_fractional_x, remainder_fractional_y = 0, 0
	local spray_tick_count = 0
	local last_tick_time = 0
	local last_nonzero_x, last_nonzero_y = 0, 0 -- Remember the last pull strength to reuse it at the end of the mag

	local function MoveMouseRelativeFractional(x, y)
		local current_time = GetRunningTime()
		-- Reset bullet counter if you stop shooting for more than 200 ms
		if current_time - last_tick_time > 200 then
			spray_tick_count = 0
		end
		spray_tick_count = spray_tick_count + 1
		last_tick_time = current_time
		
		-- RECORD LAST VALID PULL
		if y > 2 then
			last_nonzero_x = x
			last_nonzero_y = y
		end

		-- EXTRA HORIZONTAL REDUCTION: Keeps X (left/right) pull 50% weaker than Y (up/down) pull
		local horizontal_pull_modifier = 0.55

		-- INTERCEPT THE END OF THE MAGAZINE (Where the author hardcoded 0,0 and csm(1400))
		-- When x and y are 0 and we've been spraying a long time, the script is stopping early!
		if x == 0 and y == 0 and spray_tick_count > 100 then
			-- Instead of giving up or 'releasing', we artificially extend the spray for up to 4 more seconds
			for extended_tick = 1, 360 do
				if not IsMouseButtonPressed(1) then break end
				
				-- Continue the 25% late-spray pull using the last known downward velocity
				local ex_x = last_nonzero_x * 0.25 * horizontal_pull_modifier
				local ex_y = last_nonzero_y * 0.25
				
				ex_x = remainder_fractional_x + ex_x
				ex_y = remainder_fractional_y + ex_y
				local x_int_ex = math.floor(ex_x + 0.5)
				local y_int_ex = math.floor(ex_y + 0.5)
				remainder_fractional_x = ex_x - x_int_ex
				remainder_fractional_y = ex_y - y_int_ex
				MoveMouseRelative(x_int_ex, y_int_ex)
				
				csm(17) -- Same tick rate as the rest of the script
			end
			return -- We finished our extended pull, let the outer script run its 1400ms sleep
		end

		-- INITIAL PULL: Keeps the first ~15 bullets pulling normally based on what you said felt good
		local global_pull_modifier = 0.575

		-- LATE SPRAY PULL: Automatically weakens the pull drastically to stop you aiming at the floor
		if spray_tick_count > 15 then -- Reverted back to 15 ticks as it felt better originally
			global_pull_modifier = 0.25 
		end

		x = x * global_pull_modifier * horizontal_pull_modifier
		y = y * global_pull_modifier

		x = remainder_fractional_x + x
		y = remainder_fractional_y + y
		local x_int = math.floor(x + 0.5)
		local y_int = math.floor(y + 0.5)
		remainder_fractional_x = x - x_int
		remainder_fractional_y = y - y_int
		MoveMouseRelative(x_int, y_int)
	end
	function MACRO_OFFF() end
